SELECT
-- 第一组结果 (>=12)
CONCAT(
ROUND(
(SELECT AVG(

    peebr.${req.peebr}


    peebt.${req.peebtv}


    pect.${req.peect}

) FROM
prospective_basic_info pbi
LEFT JOIN
prospective_experiment_exam_blood_routine peebr
ON peebr.person_id = pbi.id AND peebr.time_point = #{req.timePoint}
LEFT JOIN
prospective_experiment_exam_biochemical_tests_v2 peebt
ON peebt.person_id = pbi.id AND peebt.time_point = #{req.timePoint}
LEFT JOIN
prospective_experiment_exam_coagulation_tests pect
ON pect.person_id = pbi.id AND pect.time_point = #{req.timePoint}
JOIN
prospective_experiment_survey_station_training_info pessti
ON pessti.person_id = pbi.id AND pessti.time_point = #{req.timePoint}
WHERE
pbi.is_vip = 'vip'
AND pessti.plateau_training_duration >= 12

    AND peebr.${req.peebr} IS NOT NULL


    AND peebt.${req.peebtv} IS NOT NULL


    AND pect.${req.peect} IS NOT NULL
),
2
),
'±',
ROUND(
(SELECT STDDEV_POP(

    peebr.${req.peebr}


    peebt.${req.peebtv}


    pect.${req.peect}

) FROM
prospective_basic_info pbi
LEFT JOIN
